module top_module(
  input clk,
  input reset_n,
  input din,
  output dout
);parameter depth = 2;

reg [depth-1:0] zz_sync_reg;
reg [depth-1:0] ff_next;

always @(posedge clk or negedge reset_n) begin
  if (~reset_n) begin
    zz_sync_reg <= {depth{1'b0}};
  end else begin
    zz_sync_reg <= {zz_sync_reg[depth-2:0], din};
  end
end

assign dout = zz_sync_reg[depth-1];

endmodule
